/*
  Smoke test de PDF (conceitual).
  - Gera o PDF via seu serviço/SDK
  - Valida metadados, páginas e tamanho
  - Produz sinais úteis para CI

  Observação: bibliotecas variam.
  - Para extrair metadados/páginas, considere pdf-lib, pdfjs-dist,
    ou uma CLI (ex.: qpdf, pdfinfo/poppler) em ambiente controlado.
*/

import crypto from 'node:crypto';
import fs from 'node:fs/promises';

const LIMITS = {
  minBytes: 30_000,
  maxBytes: 3_000_000,
  minPages: 1,
  maxPages: 30,
  requiredMeta: ['title', 'author'],
};

function sha256(buf) {
  return crypto.createHash('sha256').update(buf).digest('hex');
}

function assert(cond, msg) {
  if (!cond) throw new Error(`PDF gate failed: ${msg}`);
}

async function generatePdfBytes() {
  // Substitua por chamada real do seu gerador:
  // - HTTP (service) ou SDK local
  // Deve retornar Buffer.
  const bytes = await fs.readFile('./artifacts/sample.pdf');
  return bytes;
}

async function inspectPdf(bytes) {
  // Conceitual: retornar sinais mínimos.
  // Em implementação real, extraia metadados e páginas via biblioteca/CLI.
  return {
    meta: {
      title: 'Teste Técnico',
      author: 'Mestre André',
    },
    pages: 3,
    bytes: bytes.length,
    hash: sha256(bytes),
  };
}

async function main() {
  const bytes = await generatePdfBytes();
  const report = await inspectPdf(bytes);

  assert(report.bytes >= LIMITS.minBytes, `arquivo muito pequeno (${report.bytes})`);
  assert(report.bytes <= LIMITS.maxBytes, `arquivo muito grande (${report.bytes})`);
  assert(report.pages >= LIMITS.minPages, `poucas páginas (${report.pages})`);
  assert(report.pages <= LIMITS.maxPages, `muitas páginas (${report.pages})`);

  for (const k of LIMITS.requiredMeta) {
    assert(Boolean(report.meta?.[k]), `metadado ausente: ${k}`);
  }

  // Publique sinais para CI (stdout, JSON, etc.)
  console.log(JSON.stringify(report, null, 2));
}

main().catch((e) => {
  console.error(String(e));
  process.exit(1);
});
